class Solution:
    def countStableSubarrays(self, nums, queries):
        ans = []
        for l, r in queries:
            total = 0
            for i in range(l, r + 1):
                total += 1
                for j in range(i + 1, r + 1):
                    if nums[j] < nums[j - 1]:
                        break
                    total += 1
            ans.append(total)
        return ans

