class Solution:
    def countStableSubarrays(self, nums, queries):
        n = len(nums)
        run_start = [0] * n
        for i in range(1, n):
            run_start[i] = run_start[i - 1] if nums[i] >= nums[i - 1] else i
        run_end = [0] * n
        i = 0
        while i < n:
            j = i
            while j + 1 < n and run_start[j + 1] == run_start[i]:
                j += 1
            for t in range(i, j + 1):
                run_end[t] = j
            i = j + 1
        run_len = [idx - run_start[idx] + 1 for idx in range(n)]
        prefix = [0] * (n + 1)
        for idx in range(n):
            prefix[idx + 1] = prefix[idx] + run_len[idx]
        ans = []
        for l, r in queries:
            E = min(r, run_end[l])
            length1 = E - l + 1
            total = length1 * (length1 + 1) // 2
            if E < r:
                total += prefix[r + 1] - prefix[E + 1]
            ans.append(total)
        return ans

