var countStableSubarrays = function(nums, queries) {
    const n = nums.length;
    const runStart = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        runStart[i] = nums[i] >= nums[i - 1] ? runStart[i - 1] : i;
    }
    const runEnd = new Array(n).fill(0);
    let i = 0;
    while (i < n) {
        let j = i;
        while (j + 1 < n && runStart[j + 1] === runStart[i]) j++;
        for (let t = i; t <= j; t++) runEnd[t] = j;
        i = j + 1;
    }
    const runLen = new Array(n);
    for (let idx = 0; idx < n; idx++) runLen[idx] = idx - runStart[idx] + 1;
    const prefix = new Array(n + 1).fill(0);
    for (let idx = 0; idx < n; idx++) prefix[idx + 1] = prefix[idx] + runLen[idx];
    const ans = [];
    for (const [l, r] of queries) {
        const E = Math.min(r, runEnd[l]);
        const length1 = E - l + 1;
        let total = length1 * (length1 + 1) / 2;
        if (E < r) total += prefix[r + 1] - prefix[E + 1];
        ans.push(total);
    }
    return ans;
};
